private ExtractionInfo extractMultilineTextualBlock(JsDocToken token,
                                                  WhitespaceOption option) {

  if (token == JsDocToken.EOC || token == JsDocToken.EOL ||
      token == JsDocToken.EOF) {
    return new ExtractionInfo("", token);
  }

  stream.update();
  int startLineno = stream.getLineno();
  int startCharno = stream.getCharno() + 1;

  // Read the content from the first line.
  String line = stream.getRemainingJSDocLine();

  if (option != WhitespaceOption.PRESERVE) {
    line = line.trim();
  }

  StringBuilder builder = new StringBuilder();
  builder.append(line);

  state = State.SEARCHING_ANNOTATION;
  token = next();

  boolean ignoreStar = false;

  do {
    switch (token) {
      case STAR:
        if (!ignoreStar) {
          if (builder.length() > 0) {
            builder.append(' ');
          }

          builder.append('*');
        }

        token = next();
        continue;

      case EOL:
        if (option != WhitespaceOption.SINGLE_LINE) {
          builder.append("\n");
        }

        ignoreStar = true;
        token = next();
        continue;

      case ANNOTATION:
        if (builder.length() > 0) {
          builder.append(' ');
        }
        builder.append(toString(token));
        token = next();
        continue;

      case EOC:
      case EOF:
        // When we're capturing a license block, annotations
        // in the block are ok.
        String multilineText = builder.toString();

        if (option != WhitespaceOption.PRESERVE) {
          multilineText = multilineText.trim();
        }

        int endLineno = stream.getLineno();
        int endCharno = stream.getCharno();

        if (multilineText.length() > 0) {
          jsdocBuilder.markText(multilineText, startLineno, startCharno,
              endLineno, endCharno);
        }

        return new ExtractionInfo(multilineText, token);

      // FALL THROUGH

      default:
        ignoreStar = false;
        state = State.SEARCHING_ANNOTATION;

        if (builder.length() > 0) {
          builder.append(' ');
        }

        builder.append(toString(token));

        line = stream.getRemainingJSDocLine();

        if (option != WhitespaceOption.PRESERVE) {
          line = trimEnd(line);
        }

        builder.append(line);
        token = next();
    }
  } while (true);
}

@SuppressWarnings("fallthrough")
private ExtractionInfo extractMultilineTextualBlock(JsDocToken token,
                                                    WhitespaceOption option) {

  if (token == JsDocToken.EOC || token == JsDocToken.EOL ||
      token == JsDocToken.EOF) {
    return new ExtractionInfo("", token);
  }

  stream.update();
  int startLineno = stream.getLineno();
  int startCharno = stream.getCharno() + 1;

  // Read the content from the first line.
  String line = stream.getRemainingJSDocLine();

  if (option != WhitespaceOption.PRESERVE) {
    line = line.trim();
  }

  StringBuilder builder = new StringBuilder();
  builder.append(line);

  state = State.SEARCHING_ANNOTATION;
  token = next();

  boolean ignoreStar = false;

  do {
    switch (token) {
      case STAR:
        if (!ignoreStar) {
          if (builder.length() > 0) {
            builder.append(' ');
          }

          builder.append('*');
        }

        token = next();
        continue;

      case EOL:
        if (option != WhitespaceOption.SINGLE_LINE) {
          builder.append("\n");
        }

        ignoreStar = true;
        token = next();
        continue;

      case ANNOTATION:
        // Check if the annotation should be included in the block
        String annotationText = toString(token);
        if (shouldIncludeAnnotation(annotationText)) {
          if (builder.length() > 0) {
            builder.append(' ');
          }
          builder.append(annotationText);
        } else {
          // If the annotation should not be included, stop extraction
          String multilineText = builder.toString();

          if (option != WhitespaceOption.PRESERVE) {
            multilineText = multilineText.trim();
          }

          int endLineno = stream.getLineno();
          int endCharno = stream.getCharno();

          if (multilineText.length() > 0) {
            jsdocBuilder.markText(multilineText, startLineno, startCharno,
                endLineno, endCharno);
          }

          return new ExtractionInfo(multilineText, token);
        }
        token = next();
        continue;

      case EOC:
      case EOF:
        // When we're capturing a license block, annotations
        // in the block are ok.
        String multilineText = builder.toString();

        if (option != WhitespaceOption.PRESERVE) {
          multilineText = multilineText.trim();
        }

        int endLineno = stream.getLineno();
        int endCharno = stream.getCharno();

        if (multilineText.length() > 0) {
          jsdocBuilder.markText(multilineText, startLineno, startCharno,
              endLineno, endCharno);
        }

        return new ExtractionInfo(multilineText, token);

      // FALL THROUGH

      default:
        ignoreStar = false;
        state = State.SEARCHING_ANNOTATION;

        if (builder.length() > 0) {
          builder.append(' ');
        }

        builder.append(toString(token));

        line = stream.getRemainingJSDocLine();

        if (option != WhitespaceOption.PRESERVE) {
          line = trimEnd(line);
        }

        builder.append(line);
        token = next();
    }
  } while (true);
}

private boolean shouldIncludeAnnotation(String annotationText) {
  // Define which annotations should be included in the extracted text
  // For example, include '@license', '@author', etc.
  return annotationText.startsWith("@license") || annotationText.startsWith("@author");
}
